import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { AdminPanel } from './components/AdminPanel';
import { ChatInterface } from './components/ChatInterface';
import { Header } from './components/Header';
import { Message, Drawing, User } from './types';
import { getSolution } from './services/geminiService';
import * as db from './services/db';
import { SpinnerIcon } from './components/icons/SpinnerIcon';
import { LandingPage } from './components/LandingPage';
import { WrenchScrewdriverIcon } from './components/icons/WrenchScrewdriverIcon';
import { LoginPage } from './components/LoginPage';
import { AdminSetupPage } from './components/AdminSetupPage';
import { Notification } from './components/Notification';
import { loadPreloadedKnowledgeBase } from './services/preloader';
import { KeyIcon } from './components/icons/KeyIcon';
import { UserManagementPanel } from './components/UserManagementPanel';
import { DashboardOverview } from './components/DashboardOverview';

type AppStatus = 'landing' | 'loading' | 'setup' | 'login' | 'ready' | 'error';
type AdminView = 'overview' | 'knowledge' | 'users';

const ADMIN_EMAIL = 'admin@service.app';

const ApiKeyErrorPage: React.FC = () => (
    <div className="flex items-center justify-center h-screen w-screen bg-red-50 text-red-800">
        <div className="text-center p-8 max-w-lg">
            <KeyIcon className="h-16 w-16 mx-auto text-red-500" />
            <h1 className="text-3xl font-bold mt-4">Configuration Error</h1>
            <p className="mt-2 text-lg">
                The Gemini API key is missing.
            </p>
            <p className="mt-4 text-sm bg-red-100 p-4 rounded-md border border-red-200">
                This application cannot function without a valid API key. If you are the administrator, please ensure the <code>GEMINI_API_KEY</code> environment variable is set correctly before deploying the application.
            </p>
        </div>
    </div>
);


export default function App() {
  // App State
  const [appStatus, setAppStatus] = useState<AppStatus>('landing');

  // Auth State
  const [loggedInUser, setLoggedInUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [authError, setAuthError] = useState<string | null>(null);

  // Knowledge Base State
  const [knowledgeBaseText, setKnowledgeBaseText] = useState<string>('');
  const [drawings, setDrawings] = useState<Drawing[]>([]);

  // Chat State
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [language, setLanguage] = useState<string>('en');

  // UI State
  const [view, setView] = useState<'chat' | 'admin'>('chat');
  const [adminView, setAdminView] = useState<AdminView>('overview');
  const [notification, setNotification] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const isKnowledgeBaseLoaded = knowledgeBaseText.trim().length > 0 || drawings.length > 0;

  // Memoized stats for the dashboard
  const systemStats = useMemo(() => {
      return {
          textFilesCount: knowledgeBaseText ? (knowledgeBaseText.match(/--- End of File:/g) || []).length || 1 : 0,
          drawingsCount: drawings.length,
          usersCount: users.length,
          kbSizeKb: (knowledgeBaseText.length + JSON.stringify(drawings).length) / 1024
      };
  }, [knowledgeBaseText, drawings, users]);

  const loadKnowledgeBaseAndSetState = useCallback(async () => {
    try {
        const kbData = await db.loadKnowledgeBase();
        if (kbData && (kbData.text || kbData.drawings.length > 0)) {
            setKnowledgeBaseText(kbData.text);
            setDrawings(kbData.drawings);
            return true;
        } 

        const preloadedData = await loadPreloadedKnowledgeBase();
        if (preloadedData) {
            await db.saveKnowledgeBase(preloadedData.text, preloadedData.drawings);
            setKnowledgeBaseText(preloadedData.text);
            setDrawings(preloadedData.drawings);
            setNotification({ message: 'Default knowledge base loaded.', type: 'success' });
            return true;
        }
    } catch (error) {
        console.error("Error loading knowledge base:", error);
        setNotification({ message: 'Failed to load knowledge base.', type: 'error' });
    }
    return false;
  }, []);

  const initializeApp = useCallback(async () => {
      setAppStatus('loading');

      if (!process.env.GEMINI_API_KEY) {
        setAppStatus('error');
        return;
      }

      try {
        const hasUsers = await db.hasUsers();
        if (!hasUsers) {
          setAppStatus('setup');
          return;
        }

        const allUsers = await db.getUsers();
        setUsers(allUsers);

        const userEmail = sessionStorage.getItem('loggedInUserEmail');
        if (userEmail) {
            const user = await db.getUserByEmail(userEmail);
            if (user) {
                setLoggedInUser(user);
                await loadKnowledgeBaseAndSetState();
                setAppStatus('ready');
            } else {
                sessionStorage.removeItem('loggedInUserEmail');
                setAppStatus('login');
            }
        } else {
            setAppStatus('login');
        }
      } catch (error) {
        console.error("Initialization error:", error);
        setAppStatus('login');
      }
    }, [loadKnowledgeBaseAndSetState]);


  useEffect(() => {
    if (isKnowledgeBaseLoaded && appStatus === 'ready' && messages.length === 0) {
      const welcomeMessage: Message = {
          id: Date.now(),
          sender: 'bot',
          text: 'Welcome!',
          botResponse: {
              solutionTitle: 'Welcome to the Omega Seiki Mobility AI Assistant',
              steps: [
                { description: 'I am here to provide instant diagnostics and step-by-step troubleshooting solutions.', isSafetyWarning: false },
                { description: 'You can ask me about error codes, symptoms, or maintenance procedures.', isSafetyWarning: false },
                { description: 'To get started, please type your question in the message box below or use one of the suggestions.', isSafetyWarning: false }
              ],
              clarifyingQuestion: null,
              noSolutionFound: false,
              suggestedQueries: ["What is error E-01?", "Unit is overheating", "How to fix noisy operation"],
              drawingFileName: null,
          }
      };
      setMessages([welcomeMessage]);
    } else if (!isKnowledgeBaseLoaded && appStatus === 'ready') {
        setMessages([]);
    }
  }, [isKnowledgeBaseLoaded, appStatus]);

  const handleAdminSetup = async (password: string) => {
    try {
        const adminUser: User = { email: ADMIN_EMAIL, password, role: 'admin' };
        await db.addUser(adminUser);
        setLoggedInUser(adminUser);
        sessionStorage.setItem('loggedInUserEmail', adminUser.email);
        setUsers([adminUser]);
        await loadKnowledgeBaseAndSetState();
        setAppStatus('ready');
    } catch (e) {
        const error = e as Error;
        setAuthError(error.message);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    setAuthError(null);
    const user = await db.getUserByEmail(email.toLowerCase());
    if (user && user.password === pass) {
        setLoggedInUser(user);
        sessionStorage.setItem('loggedInUserEmail', user.email);
        await loadKnowledgeBaseAndSetState();
        setAppStatus('ready');
    } else {
        setAuthError('Invalid email or password.');
    }
  };

  const handleLogout = () => {
      setLoggedInUser(null);
      sessionStorage.removeItem('loggedInUserEmail');
      setView('chat');
      setKnowledgeBaseText('');
      setDrawings([]);
      setMessages([]);
      setAppStatus('login');
  };

  const handleAddUser = async (email: string, password: string): Promise<string | null> => {
      try {
          const newUser: User = { email: email.toLowerCase(), password, role: 'user' };
          await db.addUser(newUser);
          const allUsers = await db.getUsers();
          setUsers(allUsers);
          setNotification({ message: `User '${email}' created successfully.`, type: 'success' });
          return null;
      } catch (e) {
          const error = e as Error;
          return error.message;
      }
  };

  const handleDeleteUser = async (email: string) => {
      await db.deleteUser(email);
      const allUsers = await db.getUsers();
      setUsers(allUsers);
      setNotification({ message: `User '${email}' has been deleted.`, type: 'success' });
  };

  const handleSendMessage = useCallback(async (text: string) => {
    if (!text.trim() || !isKnowledgeBaseLoaded) return;

    const userMessage: Message = { id: Date.now(), sender: 'user', text };
    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    try {
      const drawingFileNames = drawings.map(d => d.name);
      const botResponseData = await getSolution(knowledgeBaseText, text, language, drawingFileNames);
      const botMessage: Message = {
        id: Date.now() + 1,
        sender: 'bot',
        text: 'Here is the information I found:',
        botResponse: botResponseData,
      };
      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      console.error("Error getting solution from Gemini:", error);
      const errorMessage: Message = {
        id: Date.now() + 1,
        sender: 'bot',
        text: "Sorry, I encountered an error.",
        botResponse: {
            solutionTitle: 'API Error',
            steps: [],
            clarifyingQuestion: null,
            suggestedQueries: [],
            noSolutionFound: true,
            drawingFileName: null,
            error: error instanceof Error ? error.message : "An unknown error occurred. Please check the console.",
        }
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  }, [knowledgeBaseText, drawings, isKnowledgeBaseLoaded, language]);

  const handleKnowledgeBaseUpdate = async (data: { text: string; drawings: Drawing[] }) => {
    setKnowledgeBaseText(data.text);
    setDrawings(data.drawings);
    try {
      await db.saveKnowledgeBase(data.text, data.drawings);
      setNotification({ message: 'Knowledge base updated successfully!', type: 'success' });
      // Don't auto-switch back to chat, stay in admin but maybe go to overview
      setAdminView('overview');
    } catch (error) {
      console.error("Failed to save knowledge base:", error);
      setNotification({ message: 'Failed to save knowledge base. Please try again.', type: 'error' });
    }
  };

  const handleReset = useCallback(async () => {
    if(window.confirm("Are you sure you want to reset the knowledge base? This action will clear all uploaded data from your browser and cannot be undone.")){
        setKnowledgeBaseText('');
        setDrawings([]);
        setMessages([]);
        try {
          await db.clearKnowledgeBase();
          await loadKnowledgeBaseAndSetState();
          setNotification({ message: 'Knowledge base has been reset.', type: 'success'});
        } catch (error) {
          console.error("Failed to clear knowledge base:", error);
          setNotification({ message: 'Failed to clear knowledge base.', type: 'error'});
        }
    }
  }, [loadKnowledgeBaseAndSetState]);

  const renderReadyState = () => {
    const renderContent = () => {
      if (view === 'admin' && loggedInUser?.role === 'admin') {
        return (
          <div className="flex-grow flex items-start justify-center pt-6">
            <div className="w-full max-w-4xl space-y-8">
                <div className="border-b border-gray-200">
                    <nav className="-mb-px flex space-x-8" aria-label="Tabs">
                        <button
                            onClick={() => setAdminView('overview')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-base transition-colors focus:outline-none ${adminView === 'overview' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            Overview
                        </button>
                        <button
                            onClick={() => setAdminView('knowledge')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-base transition-colors focus:outline-none ${adminView === 'knowledge' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            Knowledge Base
                        </button>
                        <button
                            onClick={() => setAdminView('users')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-base transition-colors focus:outline-none ${adminView === 'users' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            User Management
                        </button>
                    </nav>
                </div>
                {adminView === 'overview' && (
                    <DashboardOverview 
                        stats={systemStats}
                        onNavigate={setAdminView}
                    />
                )}
                {adminView === 'knowledge' && (
                    <AdminPanel 
                      onKnowledgeBaseUpdate={handleKnowledgeBaseUpdate}
                      knowledgeBaseText={knowledgeBaseText}
                      drawings={drawings}
                      isKnowledgeBaseLoaded={isKnowledgeBaseLoaded}
                    />
                )}
                {adminView === 'users' && (
                  <UserManagementPanel
                    users={users}
                    onAddUser={handleAddUser}
                    onDeleteUser={handleDeleteUser}
                  />
                )}
            </div>
          </div>
        );
      }

      if (isKnowledgeBaseLoaded) {
        return (
          <ChatInterface 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            isLoading={isLoading}
            language={language}
            drawings={drawings}
          />
        );
      }

      return (
          <div className="flex-grow flex flex-col items-center justify-center text-center p-8 text-gray-500">
              <WrenchScrewdriverIcon className="h-16 w-16 mb-4 text-gray-400" />
              <h2 className="text-2xl font-bold text-gray-700">Service AI Ready</h2>
              <p className="mt-2 max-w-md">
                  {loggedInUser?.role === 'admin' 
                    ? "The assistant is ready but the knowledge base is currently empty. Please use the Management Dashboard to upload troubleshooting documentation."
                    : "The assistant is initializing. Please wait or contact an administrator if this persists."
                  }
              </p>
              {loggedInUser?.role === 'admin' && (
                  <button 
                    onClick={() => setView('admin')}
                    className="mt-6 px-6 py-2 bg-brand-primary text-white rounded-md hover:bg-blue-800 transition-colors"
                  >
                      Go to Management Dashboard
                  </button>
              )}
          </div>
      );
    };

    return (
        <div className="flex flex-col h-screen max-w-4xl mx-auto font-sans bg-gray-100">
          <div aria-live="assertive" className="fixed inset-0 flex items-start px-4 py-6 pointer-events-none sm:p-6 sm:items-start z-50">
            <div className="w-full flex flex-col items-center space-y-4 sm:items-end">
              {notification && (
                  <Notification
                      message={notification.message}
                      type={notification.type}
                      onClose={() => setNotification(null)}
                  />
              )}
            </div>
          </div>
          <Header 
            onReset={handleReset} 
            isSheetLoaded={isKnowledgeBaseLoaded} 
            language={language}
            onLanguageChange={setLanguage}
            view={view}
            onViewToggle={() => setView(prev => prev === 'chat' ? 'admin' : 'chat')}
            user={loggedInUser}
            onLogout={handleLogout}
          />
          <main className="flex-grow flex flex-col p-4 overflow-y-auto">
            {renderContent()}
          </main>
        </div>
    );
  };

  switch(appStatus) {
    case 'landing':
      return <LandingPage onStart={initializeApp} />;
    case 'loading':
        return (
            <div className="flex items-center justify-center h-screen">
                <div className="text-center flex flex-col items-center space-y-3 text-gray-600">
                    <SpinnerIcon className="h-10 w-10 animate-spin text-brand-primary" />
                    <p className="text-lg">Preparing Dashboard...</p>
                </div>
            </div>
        );
    case 'setup':
        return <AdminSetupPage adminEmail={ADMIN_EMAIL} onSetup={handleAdminSetup} error={authError} />;
    case 'login':
        return <LoginPage onLogin={handleLogin} error={authError} onForgotPassword={() => {}} onResetPassword={() => {}} adminEmail={ADMIN_EMAIL} />;
    case 'ready':
        return renderReadyState();
    case 'error':
        return <ApiKeyErrorPage />;
    default:
        return <div className="text-red-500 text-center p-8">Invalid application state.</div>;
  }
}

import React from 'react';
import { WrenchScrewdriverIcon } from './icons/WrenchScrewdriverIcon';
import { ResetIcon } from './icons/ResetIcon';
import { LanguageIcon } from './icons/LanguageIcon';
import { Cog6ToothIcon } from './icons/Cog6ToothIcon';
import { LogoutIcon } from './icons/LogoutIcon';
import { User } from '../types';

interface HeaderProps {
    onReset: () => void;
    isSheetLoaded: boolean;
    language: string;
    onLanguageChange: (language: string) => void;
    view: 'chat' | 'admin';
    onViewToggle: () => void;
    user: User | null;
    onLogout: () => void;
}

export const Header: React.FC<HeaderProps> = ({ onReset, isSheetLoaded, language, onLanguageChange, view, onViewToggle, user, onLogout }) => {
  return (
    <header className="bg-brand-primary text-white p-4 shadow-md flex items-center justify-between transition-colors duration-300">
      <div className="flex items-center space-x-3">
        <WrenchScrewdriverIcon className="h-8 w-8 text-brand-secondary" />
        <h1 className="text-xl md:text-2xl font-bold tracking-tight">Service AI</h1>
      </div>
      <div className="flex items-center space-x-2 md:space-x-4">
        {user && view === 'chat' && (
          <div className="hidden md:flex items-center space-x-2">
              <LanguageIcon className="h-5 w-5 text-white/80"/>
              <select
                  value={language}
                  onChange={(e) => onLanguageChange(e.target.value)}
                  className="bg-brand-primary border border-brand-secondary/30 rounded-md text-white text-sm font-semibold py-1.5 pl-2 pr-7 focus:ring-2 focus:ring-brand-secondary appearance-none"
                  style={{backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%23fff' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`, backgroundPosition: 'right 0.5rem center', backgroundRepeat: 'no-repeat', backgroundSize: '1.2em 1.2em'}}
                  aria-label="Select language"
              >
                  <option value="en">English</option>
                  <option value="hi">हिन्दी</option>
                  <option value="pa">ਪੰਜਾਬੀ</option>
                  <option value="ta">தமிழ்</option>
                  <option value="kn">ಕನ್ನಡ</option>
                  <option value="gu">ગુજરાતી</option>
              </select>
          </div>
        )}

        {user?.role === 'admin' && (
          <button
              onClick={onViewToggle}
              aria-label={view === 'admin' ? "Back to Chat" : "Management Dashboard"}
              title={view === 'admin' ? "Back to Chat" : "Management Dashboard"}
              className={`flex items-center space-x-2 px-3 py-2 rounded-md transition-all duration-200 ${view === 'admin' ? 'bg-white text-brand-primary shadow-sm hover:bg-gray-100' : 'bg-brand-secondary/20 border border-brand-secondary/40 text-white hover:bg-brand-secondary/40'}`}
          >
              <Cog6ToothIcon className="h-5 w-5" />
              <span className="hidden sm:inline text-sm font-bold uppercase tracking-wide">
                {view === 'admin' ? "Exit Dashboard" : "Dashboard"}
              </span>
          </button>
        )}

        {user?.role === 'admin' && view === 'admin' && (
            <button
                onClick={onReset}
                disabled={!isSheetLoaded}
                aria-label="Reset Knowledge Base"
                title="Reset Knowledge Base"
                className="flex items-center space-x-2 px-3 py-2 rounded-md bg-yellow-500 hover:bg-yellow-600 transition-colors disabled:bg-gray-500 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
            >
                <ResetIcon className="h-5 w-5" />
                <span className="hidden sm:inline text-sm font-bold uppercase tracking-wide">Reset</span>
            </button>
        )}

        {user && (
           <button
                onClick={onLogout}
                aria-label="Logout"
                title="Logout"
                className="flex items-center p-2 rounded-md bg-red-500/10 hover:bg-red-500 text-red-400 hover:text-white transition-all duration-200"
            >
                <LogoutIcon className="h-5 w-5" />
            </button>
        )}
      </div>
    </header>
  );
};

import React, { useState } from 'react';
import { LockClosedIcon } from './icons/LockClosedIcon';
import { WrenchScrewdriverIcon } from './icons/WrenchScrewdriverIcon';

type AuthView = 'login' | 'forgotPassword' | 'resetPassword';

interface LoginPageProps {
    onLogin: (email: string, password: string) => void;
    // FIX: Added missing onForgotPassword and onResetPassword props required by App.tsx
    onForgotPassword: (email: string) => void;
    onResetPassword: (email: string, code: string, newPass: string) => void;
    error: string | null;
    adminEmail: string;
}

export const LoginPage: React.FC<LoginPageProps> = ({ onLogin, onForgotPassword, onResetPassword, error, adminEmail }) => {
    const [view, setView] = useState<AuthView>('login');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [code, setCode] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmNewPassword, setConfirmNewPassword] = useState('');
    const [localError, setLocalError] = useState<string | null>(null);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setLocalError(null);
        if (view === 'login') {
            onLogin(email, password);
        } else if (view === 'forgotPassword') {
            onForgotPassword(email);
            // We assume onForgotPassword will show a message, then we can switch view
            if (email.toLowerCase() === adminEmail.toLowerCase()) {
                setView('resetPassword');
            }
        } else if (view === 'resetPassword') {
            if (newPassword !== confirmNewPassword) {
                setLocalError("New passwords do not match.");
                return;
            }
            if(newPassword.length < 8) {
                setLocalError("Password must be at least 8 characters long.");
                return;
            }
            onResetPassword(email, code, newPassword);
        }
    };

    const renderLogin = () => (
        <>
            <div className="relative">
                <input
                    type="email"
                    autoComplete="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-4 pr-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-brand-secondary focus:border-brand-secondary transition"
                    placeholder="Email"
                />
            </div>
            <div className="relative">
                <input
                    type="password"
                    autoComplete="current-password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full pl-4 pr-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-brand-secondary focus:border-brand-secondary transition"
                    placeholder="Password"
                />
            </div>
            <div className="text-right text-sm">
                <button type="button" onClick={() => setView('forgotPassword')} className="font-semibold text-brand-primary hover:underline">
                    Forgot password?
                </button>
            </div>
        </>
    );

    const renderForgotPassword = () => (
        <>
             <p className="text-center text-gray-500 -mt-2">
                Enter your admin email address to receive a password reset code.
            </p>
            <div className="relative">
                <input
                    type="email"
                    autoComplete="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-4 pr-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-brand-secondary focus:border-brand-secondary transition"
                    placeholder="Admin Email Address"
                />
            </div>
        </>
    );

    const renderResetPassword = () => (
        <>
            <p className="text-center text-sm text-blue-700 bg-blue-100 p-3 rounded-md -mt-2">
                A verification code was sent to <span className="font-semibold">{email}</span>.
                <br /> For this demo, please use the code: <strong className="font-bold">123456</strong>
            </p>
            <input type="text" value={code} onChange={(e) => setCode(e.target.value)} placeholder="Verification Code" className="w-full p-2 border rounded-md" required />
            <input type="password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} placeholder="New Password" className="w-full p-2 border rounded-md" required />
            <input type="password" value={confirmNewPassword} onChange={(e) => setConfirmNewPassword(e.target.value)} placeholder="Confirm New Password" className="w-full p-2 border rounded-md" required />
        </>
    );

    const titles = {
        login: 'User & Admin Login',
        forgotPassword: 'Forgot Password',
        resetPassword: 'Reset Your Password'
    };

    const buttonTexts = {
        login: 'Login',
        forgotPassword: 'Send Reset Code',
        resetPassword: 'Reset Password'
    };


    return (
        <div className="flex items-center justify-center h-screen w-screen bg-gray-100 font-sans">
            <div className="w-full max-w-md p-8 space-y-6 bg-white rounded-xl shadow-lg animate-fade-in-up">
                <div className="flex flex-col items-center space-y-3">
                    <WrenchScrewdriverIcon className="h-12 w-12 text-brand-primary" />
                    <h1 className="text-3xl font-bold text-gray-900">{titles[view]}</h1>
                </div>
                <form onSubmit={handleSubmit} className="space-y-6">
                    {view === 'login' && renderLogin()}
                    {view === 'forgotPassword' && renderForgotPassword()}
                    {view === 'resetPassword' && renderResetPassword()}

                    {(error || localError) && (
                        <div className="text-sm text-center text-red-600 font-medium" role="alert">
                            {error || localError}
                        </div>
                    )}

                    <div>
                        <button
                            type="submit"
                            className="w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-brand-primary hover:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-secondary transition-colors"
                        >
                            {buttonTexts[view]}
                        </button>
                    </div>
                    {view !== 'login' && (
                         <div className="text-center text-sm">
                            <button type="button" onClick={() => setView('login')} className="font-semibold text-brand-primary hover:underline">
                                Back to Login
                            </button>
                        </div>
                    )}
                </form>
            </div>
        </div>
    );
};

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { AdminPanel } from './components/AdminPanel';
import { ChatInterface } from './components/ChatInterface';
import { Header } from './components/Header';
import { Message, Drawing, User } from './types';
import { getSolution } from './services/geminiService';
import * as db from './services/db';
import { SpinnerIcon } from './components/icons/SpinnerIcon';
import { LandingPage } from './components/LandingPage';
import { WrenchScrewdriverIcon } from './components/icons/WrenchScrewdriverIcon';
import { LoginPage } from './components/LoginPage';
import { AdminSetupPage } from './components/AdminSetupPage';
import { Notification } from './components/Notification';
import { loadPreloadedKnowledgeBase } from './services/preloader';
import { KeyIcon } from './components/icons/KeyIcon';
import { UserManagementPanel } from './components/UserManagementPanel';
import { DashboardOverview } from './components/DashboardOverview';

type AppStatus = 'landing' | 'loading' | 'setup' | 'login' | 'ready' | 'error';
type AdminView = 'overview' | 'knowledge' | 'users';

const ADMIN_EMAIL = 'admin@service.app';

const ApiKeyErrorPage: React.FC = () => (
    <div className="flex items-center justify-center h-screen w-screen bg-red-50 text-red-800">
        <div className="text-center p-8 max-w-lg">
            <KeyIcon className="h-16 w-16 mx-auto text-red-500" />
            <h1 className="text-3xl font-bold mt-4">Configuration Error</h1>
            <p className="mt-2 text-lg">
                The Gemini API key is missing.
            </p>
            <p className="mt-4 text-sm bg-red-100 p-4 rounded-md border border-red-200">
                // FIX: Use process.env.API_KEY directly as per guidelines.
                This application cannot function without a valid API key. If you are the administrator, please ensure the <code>API_KEY</code> environment variable is set correctly before deploying the application.
            </p>
        </div>
    </div>
);


export default function App() {
  // App State
  const [appStatus, setAppStatus] = useState<AppStatus>('landing');

  // Auth State
  const [loggedInUser, setLoggedInUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [authError, setAuthError] = useState<string | null>(null);

  // Knowledge Base State
  const [knowledgeBaseText, setKnowledgeBaseText] = useState<string>('');
  const [drawings, setDrawings] = useState<Drawing[]>([]);

  // Chat State
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [language, setLanguage] = useState<string>('en');

  // UI State
  const [view, setView] = useState<'chat' | 'admin'>('chat');
  const [adminView, setAdminView] = useState<AdminView>('overview');
  const [notification, setNotification] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const isKnowledgeBaseLoaded = knowledgeBaseText.trim().length > 0 || drawings.length > 0;

  // Memoized stats for the dashboard
  const systemStats = useMemo(() => {
      return {
          textFilesCount: knowledgeBaseText ? (knowledgeBaseText.match(/--- End of File:/g) || []).length || 1 : 0,
          drawingsCount: drawings.length,
          usersCount: users.length,
          kbSizeKb: (knowledgeBaseText.length + JSON.stringify(drawings).length) / 1024
      };
  }, [knowledgeBaseText, drawings, users]);

  const loadKnowledgeBaseAndSetState = useCallback(async () => {
    try {
        const kbData = await db.loadKnowledgeBase();
        if (kbData && (kbData.text || kbData.drawings.length > 0)) {
            setKnowledgeBaseText(kbData.text);
            setDrawings(kbData.drawings);
            return true;
        } 

        const preloadedData = await loadPreloadedKnowledgeBase();
        if (preloadedData) {
            await db.saveKnowledgeBase(preloadedData.text, preloadedData.drawings);
            setKnowledgeBaseText(preloadedData.text);
            setDrawings(preloadedData.drawings);
            setNotification({ message: 'Default knowledge base loaded.', type: 'success' });
            return true;
        }
    } catch (error) {
        console.error("Error loading knowledge base:", error);
        setNotification({ message: 'Failed to load knowledge base.', type: 'error' });
    }
    return false;
  }, []);

  const initializeApp = useCallback(async () => {
      setAppStatus('loading');

      // FIX: Check for process.env.API_KEY as the hard requirement for the SDK.
      if (!process.env.API_KEY) {
        setAppStatus('error');
        return;
      }

      try {
        const hasUsers = await db.hasUsers();
        if (!hasUsers) {
          setAppStatus('setup');
          return;
        }

        const allUsers = await db.getUsers();
        setUsers(allUsers);

        const userEmail = sessionStorage.getItem('loggedInUserEmail');
        if (userEmail) {
            const user = await db.getUserByEmail(userEmail);
            if (user) {
                setLoggedInUser(user);
                await loadKnowledgeBaseAndSetState();
                setAppStatus('ready');
            } else {
                sessionStorage.removeItem('loggedInUserEmail');
                setAppStatus('login');
            }
        } else {
            setAppStatus('login');
        }
      } catch (error) {
        console.error("Initialization error:", error);
        setAppStatus('login');
      }
    }, [loadKnowledgeBaseAndSetState]);


  useEffect(() => {
    if (isKnowledgeBaseLoaded && appStatus === 'ready' && messages.length === 0) {
      const welcomeMessage: Message = {
          id: Date.now(),
          sender: 'bot',
          text: 'Welcome!',
          botResponse: {
              solutionTitle: 'Welcome to the Omega Seiki Mobility AI Assistant',
              steps: [
                { description: 'I am here to provide instant diagnostics and step-by-step troubleshooting solutions.', isSafetyWarning: false },
                { description: 'You can ask me about error codes, symptoms, or maintenance procedures.', isSafetyWarning: false },
                { description: 'To get started, please type your question in the message box below or use one of the suggestions.', isSafetyWarning: false }
              ],
              clarifyingQuestion: null,
              noSolutionFound: false,
              suggestedQueries: ["What is error E-01?", "Unit is overheating", "How to fix noisy operation"],
              drawingFileName: null,
          }
      };
      setMessages([welcomeMessage]);
    } else if (!isKnowledgeBaseLoaded && appStatus === 'ready') {
        setMessages([]);
    }
  }, [isKnowledgeBaseLoaded, appStatus]);

  const handleAdminSetup = async (password: string) => {
    try {
        const adminUser: User = { email: ADMIN_EMAIL, password, role: 'admin' };
        await db.addUser(adminUser);
        setLoggedInUser(adminUser);
        sessionStorage.setItem('loggedInUserEmail', adminUser.email);
        setUsers([adminUser]);
        await loadKnowledgeBaseAndSetState();
        setAppStatus('ready');
    } catch (e) {
        const error = e as Error;
        setAuthError(error.message);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    setAuthError(null);
    const user = await db.getUserByEmail(email.toLowerCase());
    if (user && user.password === pass) {
        setLoggedInUser(user);
        sessionStorage.setItem('loggedInUserEmail', user.email);
        await loadKnowledgeBaseAndSetState();
        setAppStatus('ready');
    } else {
        setAuthError('Invalid email or password.');
    }
  };

  const handleLogout = () => {
      setLoggedInUser(null);
      sessionStorage.removeItem('loggedInUserEmail');
      setView('chat');
      setKnowledgeBaseText('');
      setDrawings([]);
      setMessages([]);
      setAppStatus('login');
  };

  const handleAddUser = async (email: string, password: string): Promise<string | null> => {
      try {
          const newUser: User = { email: email.toLowerCase(), password, role: 'user' };
          await db.addUser(newUser);
          const allUsers = await db.getUsers();
          setUsers(allUsers);
          setNotification({ message: `User '${email}' created successfully.`, type: 'success' });
          return null;
      } catch (e) {
          const error = e as Error;
          return error.message;
      }
  };

  const handleDeleteUser = async (email: string) => {
      await db.deleteUser(email);
      const allUsers = await db.getUsers();
      setUsers(allUsers);
      setNotification({ message: `User '${email}' has been deleted.`, type: 'success' });
  };

  const handleSendMessage = useCallback(async (text: string) => {
    if (!text.trim() || !isKnowledgeBaseLoaded) return;

    const userMessage: Message = { id: Date.now(), sender: 'user', text };
    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    try {
      const drawingFileNames = drawings.map(d => d.name);
      const botResponseData = await getSolution(knowledgeBaseText, text, language, drawingFileNames);
      const botMessage: Message = {
        id: Date.now() + 1,
        sender: 'bot',
        text: 'Here is the information I found:',
        botResponse: botResponseData,
      };
      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      console.error("Error getting solution from Gemini:", error);
      const errorMessage: Message = {
        id: Date.now() + 1,
        sender: 'bot',
        text: "Sorry, I encountered an error.",
        botResponse: {
            solutionTitle: 'API Error',
            steps: [],
            clarifyingQuestion: null,
            suggestedQueries: [],
            noSolutionFound: true,
            drawingFileName: null,
            error: error instanceof Error ? error.message : "An unknown error occurred. Please check the console.",
        }
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  }, [knowledgeBaseText, drawings, isKnowledgeBaseLoaded, language]);

  const handleKnowledgeBaseUpdate = async (data: { text: string; drawings: Drawing[] }) => {
    setKnowledgeBaseText(data.text);
    setDrawings(data.drawings);
    try {
      await db.saveKnowledgeBase(data.text, data.drawings);
      setNotification({ message: 'Knowledge base updated successfully!', type: 'success' });
      // Don't auto-switch back to chat, stay in admin but maybe go to overview
      setAdminView('overview');
    } catch (error) {
      console.error("Failed to save knowledge base:", error);
      setNotification({ message: 'Failed to save knowledge base. Please try again.', type: 'error' });
    }
  };

  const handleReset = useCallback(async () => {
    if(window.confirm("Are you sure you want to reset the knowledge base? This action will clear all uploaded data from your browser and cannot be undone.")){
        setKnowledgeBaseText('');
        setDrawings([]);
        setMessages([]);
        try {
          await db.clearKnowledgeBase();
          await loadKnowledgeBaseAndSetState();
          setNotification({ message: 'Knowledge base has been reset.', type: 'success'});
        } catch (error) {
          console.error("Failed to clear knowledge base:", error);
          setNotification({ message: 'Failed to clear knowledge base.', type: 'error'});
        }
    }
  }, [loadKnowledgeBaseAndSetState]);

  const renderReadyState = () => {
    const renderContent = () => {
      if (view === 'admin' && loggedInUser?.role === 'admin') {
        return (
          <div className="flex-grow flex items-start justify-center pt-6">
            <div className="w-full max-w-4xl space-y-8">
                <div className="border-b border-gray-200">
                    <nav className="-mb-px flex space-x-8" aria-label="Tabs">
                        <button
                            onClick={() => setAdminView('overview')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-base transition-colors focus:outline-none ${adminView === 'overview' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            Overview
                        </button>
                        <button
                            onClick={() => setAdminView('knowledge')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-base transition-colors focus:outline-none ${adminView === 'knowledge' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            Knowledge Base
                        </button>
                        <button
                            onClick={() => setAdminView('users')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-base transition-colors focus:outline-none ${adminView === 'users' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            User Management
                        </button>
                    </nav>
                </div>
                {adminView === 'overview' && (
                    <DashboardOverview 
                        stats={systemStats}
                        onNavigate={setAdminView}
                    />
                )}
                {adminView === 'knowledge' && (
                    <AdminPanel 
                      onKnowledgeBaseUpdate={handleKnowledgeBaseUpdate}
                      knowledgeBaseText={knowledgeBaseText}
                      drawings={drawings}
                      isKnowledgeBaseLoaded={isKnowledgeBaseLoaded}
                    />
                )}
                {adminView === 'users' && (
                  <UserManagementPanel
                    users={users}
                    onAddUser={handleAddUser}
                    onDeleteUser={handleDeleteUser}
                  />
                )}
            </div>
          </div>
        );
      }

      if (isKnowledgeBaseLoaded) {
        return (
          <ChatInterface 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            isLoading={isLoading}
            language={language}
            drawings={drawings}
          />
        );
      }

      return (
          <div className="flex-grow flex flex-col items-center justify-center text-center p-8 text-gray-500">
              <WrenchScrewdriverIcon className="h-16 w-16 mb-4 text-gray-400" />
              <h2 className="text-2xl font-bold text-gray-700">Service AI Ready</h2>
              <p className="mt-2 max-w-md">
                  {loggedInUser?.role === 'admin' 
                    ? "The assistant is ready but the knowledge base is currently empty. Please use the Management Dashboard to upload troubleshooting documentation."
                    : "The assistant is initializing. Please wait or contact an administrator if this persists."
                  }
              </p>
              {loggedInUser?.role === 'admin' && (
                  <button 
                    onClick={() => setView('admin')}
                    className="mt-6 px-6 py-2 bg-brand-primary text-white rounded-md hover:bg-blue-800 transition-colors"
                  >
                      Go to Management Dashboard
                  </button>
              )}
          </div>
      );
    };

    return (
        <div className="flex flex-col h-screen max-w-4xl mx-auto font-sans bg-gray-100">
          <div aria-live="assertive" className="fixed inset-0 flex items-start px-4 py-6 pointer-events-none sm:p-6 sm:items-start z-50">
            <div className="w-full flex flex-col items-center space-y-4 sm:items-end">
              {notification && (
                  <Notification
                      message={notification.message}
                      type={notification.type}
                      onClose={() => setNotification(null)}
                  />
              )}
            </div>
          </div>
          <Header 
            onReset={handleReset} 
            isSheetLoaded={isKnowledgeBaseLoaded} 
            language={language}
            onLanguageChange={setLanguage}
            view={view}
            onViewToggle={() => setView(prev => prev === 'chat' ? 'admin' : 'chat')}
            user={loggedInUser}
            onLogout={handleLogout}
          />
          <main className="flex-grow flex flex-col p-4 overflow-y-auto">
            {renderContent()}
          </main>
        </div>
    );
  };

  switch(appStatus) {
    case 'landing':
      return <LandingPage onStart={initializeApp} />;
    case 'loading':
        return (
            <div className="flex items-center justify-center h-screen">
                <div className="text-center flex flex-col items-center space-y-3 text-gray-600">
                    <SpinnerIcon className="h-10 w-10 animate-spin text-brand-primary" />
                    <p className="text-lg">Preparing Dashboard...</p>
                </div>
            </div>
        );
    case 'setup':
        return <AdminSetupPage adminEmail={ADMIN_EMAIL} onSetup={handleAdminSetup} error={authError} />;
    case 'login':
        // FIX: Fixed property mismatch in LoginPage call.
        return <LoginPage 
                  onLogin={handleLogin} 
                  error={authError} 
                  onForgotPassword={(email) => console.log('Forgot password for:', email)} 
                  onResetPassword={(email, code, pass) => console.log('Reset password for:', email)} 
                  adminEmail={ADMIN_EMAIL} 
               />;
    case 'ready':
        return renderReadyState();
    case 'error':
        return <ApiKeyErrorPage />;
    default:
        return <div className="text-red-500 text-center p-8">Invalid application state.</div>;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { BotResponse } from "../types";

const SYSTEM_INSTRUCTION_TEMPLATE = `You are a world-class Service Engineer AI Assistant. Your primary goal is to provide clear, accurate, and safe troubleshooting steps to field engineers. You MUST generate all responses exclusively in the user-specified language: {languageName}. Do not use any other language.`;

const PROMPT_TEMPLATE = `
You are a world-class Service Engineer AI Assistant. Your knowledge base is the provided content below.
Your task is to analyze the user's query against this data and provide a clear, step-by-step solution to help a field engineer resolve the issue.

**RULES:**
1.  **Analyze the Query:** Carefully read the user's query and find the most relevant information in the provided knowledge base content. The content could be from a spreadsheet, a presentation, or other documents.
2.  **Provide Solutions:** If a clear match is found, extract the troubleshooting steps, solution, and any safety notes. Present them as a sequence of clear, actionable steps. Synthesize information if necessary to create a coherent guide.
3.  **Prioritize Safety:** Always identify and flag any steps related to safety, electrical hazards, or required precautions. These are critical.
4.  **Ask for Clarification:** If the user's query is ambiguous, lacks detail, or could match multiple entries in the knowledge base, you MUST ask a clarifying question.
5.  **Provide Suggested Queries:** When asking a clarifying question, you MUST also provide a 'suggestedQueries' array containing 2-4 short, relevant example responses the user could click on (e.g., ["Error Code E-45", "The fan is not spinning"]). This array should be empty if you are not asking a question.
6.  **Handle No Match:** If no relevant information is found in the data after a thorough search, clearly state that you cannot find a solution in the current knowledge base. Do not invent solutions.
7.  **JSON Output:** You MUST respond ONLY with a valid JSON object that adheres to the provided schema. Do not add any text, markdown formatting, or explanations outside of the JSON object.
8.  **Language:** You MUST respond in the following language: {languageName}. All parts of your JSON response (solutionTitle, step descriptions, clarifyingQuestion, suggestedQueries) must be in {languageName}.
9.  **Include Drawings:** If a relevant drawing from the 'Available Drawings' list can visually aid the engineer, include its exact filename in the \`drawingFileName\` field. Match based on the file's name and the user's query context. Otherwise, set it to null.

**Knowledge Base Content:**
\`\`\`
{sheetData}
\`\`\`

**Available Drawings:**
{drawingFileNames}

**User Query:** "{userQuery}"
`;

const responseSchema = {
    type: Type.OBJECT,
    properties: {
        solutionTitle: {
            type: Type.STRING,
            description: "A concise title for the identified issue or solution. Null if asking a question or no solution found.",
        },
        steps: {
            type: Type.ARRAY,
            description: "An array of action items for the engineer.",
            items: {
                type: Type.OBJECT,
                properties: {
                    description: {
                        type: Type.STRING,
                        description: "A single, clear step for the solution or troubleshooting.",
                    },
                    isSafetyWarning: {
                        type: Type.BOOLEAN,
                        description: "Set to true if this step is a safety warning or critical check."
                    }
                },
                required: ["description", "isSafetyWarning"]
            },
        },
        clarifyingQuestion: {
            type: Type.STRING,
            description: "If the user's query is ambiguous, ask a relevant question here. Null otherwise.",
            nullable: true,
        },
        suggestedQueries: {
            type: Type.ARRAY,
            description: "If asking a clarifying question, provide 2-4 short, relevant suggested queries for the user to click. Empty array otherwise.",
            items: {
                type: Type.STRING,
            }
        },
        noSolutionFound: {
            type: Type.BOOLEAN,
            description: "Set to true if no solution can be found in the provided data."
        },
        drawingFileName: {
            type: Type.STRING,
            description: "The exact filename of a relevant drawing from the provided list that illustrates the solution. Null if no drawing is relevant.",
            nullable: true,
        },
    },
    required: ["solutionTitle", "steps", "clarifyingQuestion", "suggestedQueries", "noSolutionFound", "drawingFileName"]
};

const languageMap: { [key: string]: string } = {
    'en': 'English',
    'hi': 'Hindi',
    'pa': 'Punjabi',
    'ta': 'Tamil',
    'kn': 'Kannada',
    'gu': 'Gujarati',
};

export async function getSolution(sheetData: string, userQuery: string, language: string, drawingFileNames: string[]): Promise<BotResponse> {
    // FIX: Initializing GoogleGenAI with named parameter as per guidelines.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const languageName = languageMap[language] || 'English';

    const systemInstruction = SYSTEM_INSTRUCTION_TEMPLATE.replace('{languageName}', languageName);

    const prompt = PROMPT_TEMPLATE
        .replace('{sheetData}', sheetData || "No text-based knowledge provided.")
        .replace('{drawingFileNames}', drawingFileNames.length > 0 ? drawingFileNames.join(', ') : "No drawings provided.")
        .replace('{userQuery}', userQuery)
        .replace(/{languageName}/g, languageName);

    try {
        // FIX: Switched to 'gemini-3-flash-preview' for basic text/troubleshooting tasks.
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        // FIX: Accessing .text property directly (not as a method).
        const jsonText = response.text.trim();
        const parsedResponse = JSON.parse(jsonText);

        // Basic validation
        if (typeof parsedResponse.noSolutionFound !== 'boolean' || !Array.isArray(parsedResponse.steps)) {
            throw new Error("Invalid JSON structure received from API.");
        }

        return parsedResponse as BotResponse;

    } catch (error) {
        console.error("Error calling Gemini API:", error);
        if (error instanceof Error && error.message.includes('API key not valid')) {
             throw new Error("The configured Gemini API key is not valid. Please check the environment configuration.");
        }
        throw new Error("Failed to get a response from the AI model.");
    }
}

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { AdminPanel } from './components/AdminPanel';
