  const [language, setLanguage] = useState<string>('en');

  // UI State
  const [view, setView] = useState<'chat' | 'admin'>('chat');
  const [adminView, setAdminView] = useState<AdminView>('overview');
  const [notification, setNotification] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const isKnowledgeBaseLoaded = knowledgeBaseText.trim().length > 0 || drawings.length > 0;

  // Memoized stats for the dashboard
  const systemStats = useMemo(() => {
      return {
          textFilesCount: knowledgeBaseText ? (knowledgeBaseText.match(/--- End of File:/g) || []).length || (knowledgeBaseText.trim() ? 1 : 0) : 0,
          drawingsCount: drawings.length,
          usersCount: users.length,
          kbSizeKb: (knowledgeBaseText.length + JSON.stringify(drawings).length) / 1024
      };
  }, [knowledgeBaseText, drawings, users]);

  const loadKnowledgeBaseAndSetState = useCallback(async () => {
    try {
        const kbData = await db.loadKnowledgeBase();
        if (kbData && (kbData.text || kbData.drawings.length > 0)) {
            setKnowledgeBaseText(kbData.text);
            setDrawings(kbData.drawings);
            return true;
        } 

        const preloadedData = await loadPreloadedKnowledgeBase();
        if (preloadedData) {
            await db.saveKnowledgeBase(preloadedData.text, preloadedData.drawings);
            setKnowledgeBaseText(preloadedData.text);
            setDrawings(preloadedData.drawings);
            setNotification({ message: 'Default knowledge base loaded.', type: 'success' });
            return true;
        }
    } catch (error) {
        console.error("Error loading knowledge base:", error);
    }
    return false;
  }, []);

  const initializeApp = useCallback(async () => {
      setAppStatus('loading');

      if (!process.env.API_KEY) {
        setAppStatus('error');
        return;
      }

      try {
        const hasUsers = await db.hasUsers();
        if (!hasUsers) {
          setAppStatus('setup');
          return;
        }

        const allUsers = await db.getUsers();
        setUsers(allUsers);

        const userEmail = sessionStorage.getItem('loggedInUserEmail');
        if (userEmail) {
            const user = await db.getUserByEmail(userEmail);
            if (user) {
                setLoggedInUser(user);
                await loadKnowledgeBaseAndSetState();
                // Admins should land on the dashboard by default
                if (user.role === 'admin') {
                    setView('admin');
                }
                setAppStatus('ready');
            } else {
                sessionStorage.removeItem('loggedInUserEmail');
                setAppStatus('login');
            }
        } else {
            setAppStatus('login');
        }
      } catch (error) {
        console.error("Initialization error:", error);
        setAppStatus('login');
      }
    }, [loadKnowledgeBaseAndSetState]);


  useEffect(() => {
    if (isKnowledgeBaseLoaded && appStatus === 'ready' && messages.length === 0) {
      const welcomeMessage: Message = {
          id: Date.now(),
          sender: 'bot',
          text: 'Welcome!',
          botResponse: {
              solutionTitle: 'Welcome to the Omega Seiki Mobility AI Assistant',
              steps: [
                { description: 'I am here to provide instant diagnostics and step-by-step troubleshooting solutions.', isSafetyWarning: false },
                { description: 'You can ask me about error codes, symptoms, or maintenance procedures.', isSafetyWarning: false },
                { description: 'To get started, please type your question in the message box below or use one of the suggestions.', isSafetyWarning: false }
              ],
              clarifyingQuestion: null,
              noSolutionFound: false,
              suggestedQueries: ["What is error E-01?", "Unit is overheating", "How to fix noisy operation"],
              drawingFileName: null,
          }
      };
      setMessages([welcomeMessage]);
    } else if (!isKnowledgeBaseLoaded && appStatus === 'ready') {
        setMessages([]);
    }
  }, [isKnowledgeBaseLoaded, appStatus]);

  const handleAdminSetup = async (password: string) => {
    try {
        const adminUser: User = { email: ADMIN_EMAIL, password, role: 'admin' };
        await db.addUser(adminUser);
        setLoggedInUser(adminUser);
        sessionStorage.setItem('loggedInUserEmail', adminUser.email);
        setUsers([adminUser]);
        await loadKnowledgeBaseAndSetState();
        setView('admin'); // Redirect to dashboard
        setAppStatus('ready');
    } catch (e) {
        const error = e as Error;
        setAuthError(error.message);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    setAuthError(null);
    const user = await db.getUserByEmail(email.toLowerCase());
    if (user && user.password === pass) {
        setLoggedInUser(user);
        sessionStorage.setItem('loggedInUserEmail', user.email);
        await loadKnowledgeBaseAndSetState();
        if (user.role === 'admin') {
            setView('admin'); // Admins go to dashboard overview
        } else {
            setView('chat'); // Users go to chat
        }
        setAppStatus('ready');
    } else {
        setAuthError('Invalid email or password.');
    }
  };

  const handleLogout = () => {
      setLoggedInUser(null);
      sessionStorage.removeItem('loggedInUserEmail');
      setView('chat');
      setKnowledgeBaseText('');
      setDrawings([]);
      setMessages([]);
      setAppStatus('login');
  };

  const handleAddUser = async (email: string, password: string): Promise<string | null> => {
      try {
          const newUser: User = { email: email.toLowerCase(), password, role: 'user' };
          await db.addUser(newUser);
          const allUsers = await db.getUsers();
          setUsers(allUsers);
          setNotification({ message: `User '${email}' created successfully.`, type: 'success' });
          return null;
      } catch (e) {
          const error = e as Error;
          return error.message;
      }
  };

  const handleDeleteUser = async (email: string) => {
      await db.deleteUser(email);
      const allUsers = await db.getUsers();
      setUsers(allUsers);
      setNotification({ message: `User '${email}' has been deleted.`, type: 'success' });
  };

  const handleSendMessage = useCallback(async (text: string) => {
    if (!text.trim() || !isKnowledgeBaseLoaded) return;

    const userMessage: Message = { id: Date.now(), sender: 'user', text };
    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    try {
      const drawingFileNames = drawings.map(d => d.name);
      const botResponseData = await getSolution(knowledgeBaseText, text, language, drawingFileNames);
      const botMessage: Message = {
        id: Date.now() + 1,
        sender: 'bot',
        text: 'Here is the information I found:',
        botResponse: botResponseData,
      };
      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      console.error("Error getting solution from Gemini:", error);
      const errorMessage: Message = {
        id: Date.now() + 1,
        sender: 'bot',
        text: "Sorry, I encountered an error.",
        botResponse: {
            solutionTitle: 'API Error',
            steps: [],
            clarifyingQuestion: null,
            suggestedQueries: [],
            noSolutionFound: true,
            drawingFileName: null,
            error: error instanceof Error ? error.message : "An unknown error occurred. Please check the console.",
        }
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  }, [knowledgeBaseText, drawings, isKnowledgeBaseLoaded, language]);

  const handleKnowledgeBaseUpdate = async (data: { text: string; drawings: Drawing[] }) => {
    setKnowledgeBaseText(data.text);
    setDrawings(data.drawings);
    try {
      await db.saveKnowledgeBase(data.text, data.drawings);
      setNotification({ message: 'Knowledge base updated successfully!', type: 'success' });
      setAdminView('overview'); // Go back to overview to see updated stats
    } catch (error) {
      console.error("Failed to save knowledge base:", error);
      setNotification({ message: 'Failed to save knowledge base. Please try again.', type: 'error' });
    }
  };

  const handleReset = useCallback(async () => {
    if(window.confirm("Are you sure you want to reset the knowledge base? This action will clear all uploaded data from your browser and cannot be undone.")){
        setKnowledgeBaseText('');
        setDrawings([]);
        setMessages([]);
        try {
          await db.clearKnowledgeBase();
          await loadKnowledgeBaseAndSetState();
          setNotification({ message: 'Knowledge base has been reset.', type: 'success'});
        } catch (error) {
          console.error("Failed to clear knowledge base:", error);
          setNotification({ message: 'Failed to clear knowledge base.', type: 'error'});
        }
    }
  }, [loadKnowledgeBaseAndSetState]);

  const renderReadyState = () => {
    const renderContent = () => {
      // If we are in admin view, show admin components
      if (view === 'admin' && loggedInUser?.role === 'admin') {
        return (
          <div className="flex-grow flex items-start justify-center pt-6">
            <div className="w-full max-w-4xl space-y-8">
                <div className="border-b border-gray-200">
                    <nav className="-mb-px flex space-x-8" aria-label="Tabs">
                        <button
                            onClick={() => setAdminView('overview')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-bold text-lg transition-colors focus:outline-none ${adminView === 'overview' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            Hub Overview
                        </button>
                        <button
                            onClick={() => setAdminView('knowledge')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-bold text-lg transition-colors focus:outline-none ${adminView === 'knowledge' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            Knowledge Base
                        </button>
                        <button
                            onClick={() => setAdminView('users')}
                            className={`whitespace-nowrap py-3 px-1 border-b-2 font-bold text-lg transition-colors focus:outline-none ${adminView === 'users' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                        >
                            Users
                        </button>
                    </nav>
                </div>
                {adminView === 'overview' && (
                    <DashboardOverview 
                        stats={systemStats}
                        onNavigate={setAdminView}
                    />
                )}
                {adminView === 'knowledge' && (
                    <AdminPanel 
                      onKnowledgeBaseUpdate={handleKnowledgeBaseUpdate}
                      knowledgeBaseText={knowledgeBaseText}
                      drawings={drawings}
                      isKnowledgeBaseLoaded={isKnowledgeBaseLoaded}
                    />
                )}
                {adminView === 'users' && (
                  <UserManagementPanel
                    users={users}
                    onAddUser={handleAddUser}
                    onDeleteUser={handleDeleteUser}
                  />
                )}
            </div>
          </div>
        );
      }

      // Otherwise show chat or empty state
      if (isKnowledgeBaseLoaded) {
        return (
          <ChatInterface 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            isLoading={isLoading}
            language={language}
            drawings={drawings}
          />
        );
      }

      return (
          <div className="flex-grow flex flex-col items-center justify-center text-center p-8 text-gray-500">
              <div className="bg-gray-200 p-8 rounded-full mb-6">
                <WrenchScrewdriverIcon className="h-16 w-16 text-gray-400" />
              </div>
              <h2 className="text-3xl font-bold text-gray-800 tracking-tight">System Ready & Awaiting Content</h2>
              <p className="mt-4 text-lg max-w-lg text-gray-600">
                  {loggedInUser?.role === 'admin' 
                    ? "The assistant is online, but your local knowledge base is empty. Head to the Management Hub to upload your first technical documents."
                    : "The system is being updated by administrators. Please wait or contact support for access to specific technical data."
                  }
              </p>
              {loggedInUser?.role === 'admin' && (
                  <button 
                    onClick={() => { setView('admin'); setAdminView('knowledge'); }}
                    className="mt-8 px-8 py-3 bg-brand-primary text-white font-bold rounded-lg shadow-lg hover:bg-blue-800 transition-all transform hover:scale-105"
                  >
                      Go to Knowledge Management
                  </button>
              )}
          </div>
      );
    };

    return (
        <div className="flex flex-col h-screen max-w-4xl mx-auto font-sans bg-gray-100">
          <div aria-live="assertive" className="fixed inset-0 flex items-start px-4 py-6 pointer-events-none sm:p-6 sm:items-start z-50">
            <div className="w-full flex flex-col items-center space-y-4 sm:items-end">
              {notification && (
                  <Notification
                      message={notification.message}
                      type={notification.type}
                      onClose={() => setNotification(null)}
                  />
              )}
            </div>
          </div>
          <Header 
            onReset={handleReset} 
            isSheetLoaded={isKnowledgeBaseLoaded} 
            language={language}
            onLanguageChange={setLanguage}
            view={view}
            onViewToggle={() => setView(prev => prev === 'chat' ? 'admin' : 'chat')}
            user={loggedInUser}
            onLogout={handleLogout}
          />
          <main className="flex-grow flex flex-col p-4 overflow-y-auto">
            {renderContent()}
          </main>
        </div>
    );
  };

  switch(appStatus) {
    case 'landing':
      return <LandingPage onStart={initializeApp} />;
    case 'loading':
        return (
            <div className="flex items-center justify-center h-screen bg-gray-50">
                <div className="text-center flex flex-col items-center space-y-4 text-gray-600">
                    <SpinnerIcon className="h-12 w-12 animate-spin text-brand-primary" />
                    <p className="text-xl font-medium">Initializing Management Hub...</p>
                </div>
            </div>
        );
    case 'setup':
        return <AdminSetupPage adminEmail={ADMIN_EMAIL} onSetup={handleAdminSetup} error={authError} />;
    case 'login':
        return <LoginPage 
                  onLogin={handleLogin} 
                  error={authError} 
                  onForgotPassword={(email) => console.log('Reset request for:', email)} 
                  onResetPassword={(email, code, pass) => console.log('Password reset execution')} 
                  adminEmail={ADMIN_EMAIL} 
               />;
    case 'ready':
        return renderReadyState();
    case 'error':
        return <ApiKeyErrorPage />;
    default:
        return <div className="text-red-500 text-center p-8">Application state error.</div>;
  }
}

import React from 'react';
import { WrenchScrewdriverIcon } from './icons/WrenchScrewdriverIcon';
import { ResetIcon } from './icons/ResetIcon';
import { LanguageIcon } from './icons/LanguageIcon';
import { Cog6ToothIcon } from './icons/Cog6ToothIcon';
import { LogoutIcon } from './icons/LogoutIcon';
import { BotIcon } from './icons/BotIcon';
import { User } from '../types';

interface HeaderProps {
    onReset: () => void;
    isSheetLoaded: boolean;
    language: string;
    onLanguageChange: (language: string) => void;
    view: 'chat' | 'admin';
    onViewToggle: () => void;
    user: User | null;
    onLogout: () => void;
}

export const Header: React.FC<HeaderProps> = ({ onReset, isSheetLoaded, language, onLanguageChange, view, onViewToggle, user, onLogout }) => {
  return (
    <header className="bg-brand-primary text-white p-4 shadow-md flex items-center justify-between transition-all duration-300 z-10">
      <div className="flex items-center space-x-3">
        <WrenchScrewdriverIcon className="h-8 w-8 text-brand-secondary" />
        <div className="flex flex-col">
            <h1 className="text-lg md:text-xl font-bold tracking-tight leading-none">Service AI</h1>
            <span className="text-[10px] uppercase tracking-widest text-brand-secondary font-black">Management Hub</span>
        </div>
      </div>

      <div className="flex items-center space-x-2 md:space-x-3">
        {user && view === 'chat' && (
          <div className="hidden lg:flex items-center space-x-2 bg-black/10 px-3 py-1.5 rounded-lg border border-white/10">
              <LanguageIcon className="h-4 w-4 text-white/70"/>
              <select
                  value={language}
                  onChange={(e) => onLanguageChange(e.target.value)}
                  className="bg-transparent border-none text-white text-xs font-bold focus:ring-0 cursor-pointer pr-6"
                  style={{backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%23fff' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`, backgroundPosition: 'right 0.2rem center', backgroundRepeat: 'no-repeat', backgroundSize: '1em 1em'}}
                  aria-label="Select language"
              >
                  <option className="bg-brand-primary" value="en">English</option>
                  <option className="bg-brand-primary" value="hi">हिन्दी</option>
                  <option className="bg-brand-primary" value="pa">ਪੰਜਾਬੀ</option>
                  <option className="bg-brand-primary" value="ta">தமிழ்</option>
                  <option className="bg-brand-primary" value="kn">ಕನ್ನಡ</option>
                  <option className="bg-brand-primary" value="gu">ગુજરાતી</option>
              </select>
          </div>
        )}

        {user?.role === 'admin' && (
          <button
              onClick={onViewToggle}
              className={`flex items-center space-x-2 px-4 py-2 rounded-lg transition-all duration-300 border-2 ${
                  view === 'admin' 
                  ? 'bg-white text-brand-primary border-white font-bold shadow-lg' 
                  : 'bg-brand-secondary/30 text-white border-brand-secondary/50 hover:bg-brand-secondary/50'
              }`}
          >
              {view === 'admin' ? <BotIcon className="h-5 w-5" /> : <Cog6ToothIcon className="h-5 w-5" />}
              <span className="text-sm font-bold uppercase tracking-wide">
                {view === 'admin' ? "Console" : "Hub"}
              </span>
          </button>
        )}

        {user?.role === 'admin' && view === 'admin' && (
            <button
                onClick={onReset}
                disabled={!isSheetLoaded}
                title="Wipe Local Knowledge Base"
                className="flex items-center p-2 rounded-lg bg-red-500 hover:bg-red-600 transition-colors disabled:opacity-30 disabled:cursor-not-allowed shadow-sm"
            >
                <ResetIcon className="h-5 w-5" />
            </button>
        )}

        {user && (
           <button
                onClick={onLogout}
                className="flex items-center p-2 rounded-lg bg-black/20 hover:bg-black/40 text-white/80 transition-all duration-200"
                title="Sign Out"
            >
                <LogoutIcon className="h-5 w-5" />
            </button>
        )}
      </div>
    </header>
  );
};

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { AdminPanel } from './components/AdminPanel';
import { ChatInterface } from './components/ChatInterface';
import { Header } from './components/Header';
import { Message, Drawing, User } from './types';
import { getSolution } from './services/geminiService';
import * as db from './services/db';
import { SpinnerIcon } from './components/icons/SpinnerIcon';
import { LandingPage } from './components/LandingPage';
import { WrenchScrewdriverIcon } from './components/icons/WrenchScrewdriverIcon';
import { LoginPage } from './components/LoginPage';
import { AdminSetupPage } from './components/AdminSetupPage';
import { Notification } from './components/Notification';
import { loadPreloadedKnowledgeBase } from './services/preloader';
import { KeyIcon } from './components/icons/KeyIcon';
import { UserManagementPanel } from './components/UserManagementPanel';
import { DashboardOverview } from './components/DashboardOverview';

type AppStatus = 'landing' | 'loading' | 'setup' | 'login' | 'ready' | 'error';
type AdminView = 'overview' | 'knowledge' | 'users';

const ADMIN_EMAIL = 'admin@service.app';

const ApiKeyErrorPage: React.FC = () => (
    <div className="flex items-center justify-center h-screen w-screen bg-red-50 text-red-800">
        <div className="text-center p-8 max-w-lg">
            <KeyIcon className="h-16 w-16 mx-auto text-red-500" />
            <h1 className="text-3xl font-bold mt-4">Configuration Error</h1>
            <p className="mt-2 text-lg">
                The Gemini API key is missing.
            </p>
            <p className="mt-4 text-sm bg-red-100 p-4 rounded-md border border-red-200">
                This application cannot function without a valid API key. Ensure the <code>API_KEY</code> environment variable is set correctly in your environment.
            </p>
        </div>
    </div>
);

export default function App() {
  // App State
  const [appStatus, setAppStatus] = useState<AppStatus>('landing');

  // Auth State
  const [loggedInUser, setLoggedInUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [authError, setAuthError] = useState<string | null>(null);

  // Knowledge Base State
  const [knowledgeBaseText, setKnowledgeBaseText] = useState<string>('');
  const [drawings, setDrawings] = useState<Drawing[]>([]);

  // Chat State
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [language, setLanguage] = useState<string>('en');

  // UI State
  const [view, setView] = useState<'chat' | 'admin'>('chat');
  const [adminView, setAdminView] = useState<AdminView>('overview');
  const [notification, setNotification] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const isKnowledgeBaseLoaded = knowledgeBaseText.trim().length > 0 || drawings.length > 0;

  // Dynamic system stats calculation
  const systemStats = useMemo(() => {
      return {
          textFilesCount: knowledgeBaseText ? (knowledgeBaseText.match(/--- End of File:/g) || []).length || (knowledgeBaseText.trim() ? 1 : 0) : 0,
          drawingsCount: drawings.length,
          usersCount: users.length,
          kbSizeKb: (knowledgeBaseText.length + JSON.stringify(drawings).length) / 1024
      };
  }, [knowledgeBaseText, drawings, users]);

  const loadKnowledgeBaseAndSetState = useCallback(async () => {
    try {
        const kbData = await db.loadKnowledgeBase();
        if (kbData && (kbData.text || kbData.drawings.length > 0)) {
            setKnowledgeBaseText(kbData.text);
            setDrawings(kbData.drawings);
            return true;
        } 

        const preloadedData = await loadPreloadedKnowledgeBase();
        if (preloadedData) {
            await db.saveKnowledgeBase(preloadedData.text, preloadedData.drawings);
            setKnowledgeBaseText(preloadedData.text);
            setDrawings(preloadedData.drawings);
            return true;
        }
    } catch (error) {
        console.error("Error loading knowledge base:", error);
    }
    return false;
  }, []);

  const initializeApp = useCallback(async () => {
      setAppStatus('loading');

      if (!process.env.API_KEY) {
        setAppStatus('error');
        return;
      }

      try {
        const hasUsers = await db.hasUsers();
        if (!hasUsers) {
          setAppStatus('setup');
          return;
        }

        const allUsers = await db.getUsers();
        setUsers(allUsers);

        const userEmail = sessionStorage.getItem('loggedInUserEmail');
        if (userEmail) {
            const user = await db.getUserByEmail(userEmail);
            if (user) {
                setLoggedInUser(user);
                await loadKnowledgeBaseAndSetState();
                if (user.role === 'admin') setView('admin');
                setAppStatus('ready');
            } else {
                sessionStorage.removeItem('loggedInUserEmail');
                setAppStatus('login');
            }
        } else {
            setAppStatus('login');
        }
      } catch (error) {
        setAppStatus('login');
      }
    }, [loadKnowledgeBaseAndSetState]);

  useEffect(() => {
    if (isKnowledgeBaseLoaded && appStatus === 'ready' && messages.length === 0) {
      const welcomeMessage: Message = {
          id: Date.now(),
          sender: 'bot',
          text: 'Welcome!',
          botResponse: {
              solutionTitle: 'Welcome to the Omega Seiki Mobility AI Assistant',
              steps: [
                { description: 'I am here to provide instant diagnostics and step-by-step troubleshooting solutions.', isSafetyWarning: false },
                { description: 'You can ask me about error codes, symptoms, or maintenance procedures.', isSafetyWarning: false }
              ],
              clarifyingQuestion: null,
              noSolutionFound: false,
              suggestedQueries: ["What is error E-01?", "Unit is overheating"],
              drawingFileName: null,
          }
      };
      setMessages([welcomeMessage]);
    }
  }, [isKnowledgeBaseLoaded, appStatus, messages.length]);

  const handleAdminSetup = async (password: string) => {
    try {
        const adminUser: User = { email: ADMIN_EMAIL, password, role: 'admin' };
        await db.addUser(adminUser);
        setLoggedInUser(adminUser);
        sessionStorage.setItem('loggedInUserEmail', adminUser.email);
        setUsers([adminUser]);
        await loadKnowledgeBaseAndSetState();
        setView('admin');
        setAppStatus('ready');
    } catch (e) {
        setAuthError((e as Error).message);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    setAuthError(null);
    const user = await db.getUserByEmail(email.toLowerCase());
    if (user && user.password === pass) {
        setLoggedInUser(user);
        sessionStorage.setItem('loggedInUserEmail', user.email);
        await loadKnowledgeBaseAndSetState();
        setView(user.role === 'admin' ? 'admin' : 'chat');
        setAppStatus('ready');
    } else {
        setAuthError('Invalid email or password.');
    }
  };

  const handleLogout = () => {
      setLoggedInUser(null);
      sessionStorage.removeItem('loggedInUserEmail');
      setView('chat');
      setKnowledgeBaseText('');
      setDrawings([]);
      setMessages([]);
      setAppStatus('login');
  };

  const handleAddUser = async (email: string, password: string): Promise<string | null> => {
      try {
          const newUser: User = { email: email.toLowerCase(), password, role: 'user' };
          await db.addUser(newUser);
          const allUsers = await db.getUsers();
          setUsers(allUsers);
          setNotification({ message: `User '${email}' created.`, type: 'success' });
          return null;
      } catch (e) {
          return (e as Error).message;
      }
  };

  const handleDeleteUser = async (email: string) => {
      await db.deleteUser(email);
      const allUsers = await db.getUsers();
      setUsers(allUsers);
      setNotification({ message: `User '${email}' deleted.`, type: 'success' });
  };

  const handleSendMessage = useCallback(async (text: string) => {
    if (!text.trim() || !isKnowledgeBaseLoaded) return;
    const userMessage: Message = { id: Date.now(), sender: 'user', text };
    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    try {
      const botResponseData = await getSolution(knowledgeBaseText, text, language, drawings.map(d => d.name));
      setMessages(prev => [...prev, { id: Date.now() + 1, sender: 'bot', text: 'Solution:', botResponse: botResponseData }]);
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now() + 1, sender: 'bot', text: "Error encountered.", botResponse: { solutionTitle: 'API Error', steps: [], clarifyingQuestion: null, suggestedQueries: [], noSolutionFound: true, drawingFileName: null, error: (error as Error).message } }]);
    } finally {
      setIsLoading(false);
    }
  }, [knowledgeBaseText, drawings, isKnowledgeBaseLoaded, language]);

  const handleKnowledgeBaseUpdate = async (data: { text: string; drawings: Drawing[] }) => {
    setKnowledgeBaseText(data.text);
    setDrawings(data.drawings);
    try {
      await db.saveKnowledgeBase(data.text, data.drawings);
      setNotification({ message: 'Hub content updated.', type: 'success' });
      setAdminView('overview');
    } catch (error) {
      setNotification({ message: 'Update failed.', type: 'error' });
    }
  };

  const handleReset = useCallback(async () => {
    if(window.confirm("Wipe all local knowledge base data?")){
        setKnowledgeBaseText('');
        setDrawings([]);
        setMessages([]);
        try {
          await db.clearKnowledgeBase();
          await loadKnowledgeBaseAndSetState();
          setNotification({ message: 'Hub reset.', type: 'success'});
        } catch (error) {
          setNotification({ message: 'Reset failed.', type: 'error'});
        }
    }
  }, [loadKnowledgeBaseAndSetState]);

  const renderReadyState = () => {
    const renderContent = () => {
      // PRIORITY 1: For Administrators, always show the Management Hub if view is 'admin' OR if KB is empty
      if (loggedInUser?.role === 'admin') {
        if (view === 'admin' || !isKnowledgeBaseLoaded) {
          return (
            <div className="flex-grow flex items-start justify-center pt-2">
              <div className="w-full max-w-4xl space-y-6">
                  {/* Admin Header Context */}
                  <div className="flex items-center justify-between px-2">
                      <div className="flex items-center space-x-2">
                          <span className="flex h-3 w-3 relative">
                            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand-secondary opacity-75"></span>
                            <span className="relative inline-flex rounded-full h-3 w-3 bg-brand-secondary"></span>
                          </span>
                          <span className="text-xs font-black uppercase tracking-widest text-brand-primary">Administrator Session</span>
                      </div>
                  </div>

                  <div className="border-b border-gray-200">
                      <nav className="-mb-px flex space-x-8" aria-label="Tabs">
                          {['overview', 'knowledge', 'users'].map((v) => (
                              <button
                                  key={v}
                                  onClick={() => setAdminView(v as AdminView)}
                                  className={`whitespace-nowrap py-3 px-1 border-b-2 font-bold text-lg transition-colors capitalize ${adminView === v ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}
                              >
                                  {v === 'overview' ? 'Hub Overview' : v === 'knowledge' ? 'Knowledge Base' : 'User Access'}
                              </button>
                          ))}
                      </nav>
                  </div>
                  {adminView === 'overview' && <DashboardOverview stats={systemStats} onNavigate={setAdminView} />}
                  {adminView === 'knowledge' && <AdminPanel onKnowledgeBaseUpdate={handleKnowledgeBaseUpdate} knowledgeBaseText={knowledgeBaseText} drawings={drawings} isKnowledgeBaseLoaded={isKnowledgeBaseLoaded} />}
                  {adminView === 'users' && <UserManagementPanel users={users} onAddUser={handleAddUser} onDeleteUser={handleDeleteUser} />}
              </div>
            </div>
          );
        }
      }

      // PRIORITY 2: Standard user experience or Admin explicitly switching to Chat
      if (isKnowledgeBaseLoaded) {
        return <ChatInterface messages={messages} onSendMessage={handleSendMessage} isLoading={isLoading} language={language} drawings={drawings} />;
      }

      // PRIORITY 3: Standard user seeing empty state
      return (
          <div className="flex-grow flex flex-col items-center justify-center text-center p-8 text-gray-500">
              <div className="bg-gray-200 p-8 rounded-full mb-6">
                <WrenchScrewdriverIcon className="h-16 w-16 text-gray-400" />
              </div>
              <h2 className="text-3xl font-bold text-gray-800 tracking-tight">Technical Data Offline</h2>
              <p className="mt-4 text-lg max-w-lg text-gray-600">
                  The local knowledge base is empty. Please contact an administrator to upload troubleshooting documentation.
              </p>
          </div>
      );
    };

    return (
        <div className="flex flex-col h-screen max-w-4xl mx-auto font-sans bg-gray-50">
          <div className="fixed inset-0 flex items-start px-4 py-6 pointer-events-none sm:p-6 sm:items-start z-50">
            <div className="w-full flex flex-col items-center space-y-4 sm:items-end">
              {notification && <Notification message={notification.message} type={notification.type} onClose={() => setNotification(null)} />}
            </div>
          </div>
          <Header 
            onReset={handleReset} 
            isSheetLoaded={isKnowledgeBaseLoaded} 
            language={language}
            onLanguageChange={setLanguage}
            view={view}
            onViewToggle={() => setView(prev => prev === 'chat' ? 'admin' : 'chat')}
            user={loggedInUser}
            onLogout={handleLogout}
          />
          <main className="flex-grow flex flex-col p-4 overflow-y-auto">
            {renderContent()}
          </main>
        </div>
    );
  };

  switch(appStatus) {
    case 'landing': return <LandingPage onStart={initializeApp} />;
    case 'loading': return (
        <div className="flex items-center justify-center h-screen bg-white">
            <div className="text-center flex flex-col items-center space-y-4">
                <SpinnerIcon className="h-12 w-12 animate-spin text-brand-primary" />
                <p className="text-xl font-medium text-gray-500">Syncing Technical Data...</p>
            </div>
        </div>
    );
    case 'setup': return <AdminSetupPage adminEmail={ADMIN_EMAIL} onSetup={handleAdminSetup} error={authError} />;
    case 'login': return <LoginPage onLogin={handleLogin} error={authError} onForgotPassword={() => {}} onResetPassword={() => {}} adminEmail={ADMIN_EMAIL} />;
    case 'ready': return renderReadyState();
    case 'error': return <ApiKeyErrorPage />;
    default: return <div className="p-8">System Error</div>;
  }
}

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { AdminPanel } from './components/AdminPanel';
import { ChatInterface } from './components/ChatInterface';
import { Header } from './components/Header';
import { Message, Drawing } from './types';
import { getSolution } from './services/geminiService';
import * as db from './services/db';
import { SpinnerIcon } from './components/icons/SpinnerIcon';
import { Notification } from './components/Notification';
import { loadPreloadedKnowledgeBase } from './services/preloader';
import { DashboardOverview } from './components/DashboardOverview';

type AppStatus = 'loading' | 'ready' | 'error';
type AdminView = 'overview' | 'knowledge';

export default function App() {
  const [appStatus, setAppStatus] = useState<AppStatus>('loading');
  const [knowledgeBaseText, setKnowledgeBaseText] = useState<string>('');
  const [drawings, setDrawings] = useState<Drawing[]>([]);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [language, setLanguage] = useState<string>('en');
  const [view, setView] = useState<'chat' | 'admin'>('admin'); // Default to Hub/Dashboard
  const [adminView, setAdminView] = useState<AdminView>('overview');
  const [notification, setNotification] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const isKnowledgeBaseLoaded = knowledgeBaseText.trim().length > 0 || drawings.length > 0;

  const systemStats = useMemo(() => {
      const docMatches = knowledgeBaseText.match(/--- End of File:/g);
      return {
          textFilesCount: docMatches ? docMatches.length : (knowledgeBaseText.trim() ? 1 : 0),
          drawingsCount: drawings.length,
          usersCount: 1, // Single user mode
          kbSizeKb: (knowledgeBaseText.length + JSON.stringify(drawings).length) / 1024
      };
  }, [knowledgeBaseText, drawings]);

  const loadData = useCallback(async () => {
    try {
        let kbData = await db.loadKnowledgeBase();

        // If empty, force load preloaded data
        if (!kbData || (!kbData.text && kbData.drawings.length === 0)) {
            const preloaded = await loadPreloadedKnowledgeBase();
            if (preloaded) {
                await db.saveKnowledgeBase(preloaded.text, preloaded.drawings);
                kbData = preloaded;
                setNotification({ message: 'Preloaded knowledge base activated.', type: 'success' });
            }
        }

        if (kbData) {
            setKnowledgeBaseText(kbData.text);
            setDrawings(kbData.drawings);
        }
        return true;
    } catch (error) {
        console.error("Data load error:", error);
        return false;
    }
  }, []);

  useEffect(() => {
    const init = async () => {
      if (!process.env.API_KEY) {
        setAppStatus('error');
        return;
      }
      await loadData();
      setAppStatus('ready');
    };
    init();
  }, [loadData]);

  const handleSendMessage = useCallback(async (text: string) => {
    if (!text.trim() || !isKnowledgeBaseLoaded) return;
    const userMsg: Message = { id: Date.now(), sender: 'user', text };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const solution = await getSolution(knowledgeBaseText, text, language, drawings.map(d => d.name));
      setMessages(prev => [...prev, { id: Date.now() + 1, sender: 'bot', text: 'Response:', botResponse: solution }]);
    } catch (error) {
      setNotification({ message: 'AI Connection Error', type: 'error' });
    } finally {
      setIsLoading(false);
    }
  }, [knowledgeBaseText, drawings, isKnowledgeBaseLoaded, language]);

  const handleReset = useCallback(async () => {
    if (window.confirm("Wipe local data and reload preloaded defaults?")) {
        await db.clearKnowledgeBase();
        const preloaded = await loadPreloadedKnowledgeBase();
        if (preloaded) {
            await db.saveKnowledgeBase(preloaded.text, preloaded.drawings);
            setKnowledgeBaseText(preloaded.text);
            setDrawings(preloaded.drawings);
            setMessages([]);
            setNotification({ message: 'System Re-initialized.', type: 'success' });
        }
    }
  }, []);

  if (appStatus === 'error') {
    return (
        <div className="flex items-center justify-center h-screen bg-red-50 p-6 text-center">
            <div className="max-w-md">
                <h1 className="text-2xl font-bold text-red-800">Configuration Error</h1>
                <p className="mt-2 text-red-600">API_KEY is missing. Please check your environment variables.</p>
            </div>
        </div>
    );
  }

  if (appStatus === 'loading') {
    return (
        <div className="flex items-center justify-center h-screen bg-white">
            <div className="text-center">
                <SpinnerIcon className="h-12 w-12 animate-spin text-brand-primary mx-auto" />
                <p className="mt-4 text-gray-500 font-medium tracking-tight">Syncing Hub Data...</p>
            </div>
        </div>
    );
  }

  return (
    <div className="flex flex-col h-screen max-w-5xl mx-auto font-sans bg-gray-50 border-x border-gray-200 shadow-2xl">
      <div className="fixed top-4 right-4 z-50 pointer-events-none">
          {notification && <Notification message={notification.message} type={notification.type} onClose={() => setNotification(null)} />}
      </div>

      <Header 
        onReset={handleReset} 
        isSheetLoaded={isKnowledgeBaseLoaded} 
        language={language}
        onLanguageChange={setLanguage}
        view={view}
        onViewToggle={() => setView(v => v === 'chat' ? 'admin' : 'chat')}
        user={null}
        onLogout={() => {}}
      />

      <main className="flex-grow flex flex-col p-6 overflow-y-auto">
        {view === 'admin' ? (
            <div className="space-y-8 animate-fade-in-up">
                <div className="flex items-center justify-between">
                    <h2 className="text-3xl font-black text-gray-900 tracking-tighter">Management Hub</h2>
                    <div className="flex space-x-2">
                        <button 
                            onClick={() => setAdminView('overview')}
                            className={`px-4 py-2 rounded-lg font-bold text-sm transition-all ${adminView === 'overview' ? 'bg-brand-primary text-white shadow-lg' : 'text-gray-500 hover:bg-gray-200'}`}
                        >
                            Overview
                        </button>
                        <button 
                            onClick={() => setAdminView('knowledge')}
                            className={`px-4 py-2 rounded-lg font-bold text-sm transition-all ${adminView === 'knowledge' ? 'bg-brand-primary text-white shadow-lg' : 'text-gray-500 hover:bg-gray-200'}`}
                        >
                            Knowledge Base
                        </button>
                    </div>
                </div>

                {adminView === 'overview' ? (
                    <DashboardOverview stats={systemStats} onNavigate={(v) => {
                        if (v === 'knowledge') setAdminView('knowledge');
                        else setView('chat');
                    }} />
                ) : (
                    <AdminPanel 
                        onKnowledgeBaseUpdate={(data) => {
                            setKnowledgeBaseText(data.text);
                            setDrawings(data.drawings);
                            db.saveKnowledgeBase(data.text, data.drawings);
                            setNotification({ message: 'Knowledge base updated.', type: 'success' });
                            setAdminView('overview');
                        }}
                        knowledgeBaseText={knowledgeBaseText}
                        drawings={drawings}
                        isKnowledgeBaseLoaded={isKnowledgeBaseLoaded}
                    />
                )}
            </div>
        ) : (
            <ChatInterface 
                messages={messages} 
                onSendMessage={handleSendMessage} 
                isLoading={isLoading} 
                language={language} 
                drawings={drawings} 
            />
        )}
      </main>
    </div>
  );
}

